use std::collections::HashSet;
use std::io::{self, Write};

fn main() -> io::Result<()> {
    let mut input_data = Vec::<String>::new();
    println!("Enter some strings, one per line. Press Ctrl+D (or Ctrl+Z then Enter on Windows) when done:");

    let mut handle = io::stdin();
    for line in handle.lines() {
        match line? {
            s if !s.trim().is_empty() => input_data.push(s),
            _ => break,
        }
    }

    let unique_set: HashSet<String> = input_data.into_iter().collect();
    let mut sorted_unique: Vec<String> = unique_set.into_iter().collect();
    sorted_unique.sort();

    println!("n--- Unique and Sorted Results ---");
    for item in sorted_unique {
        writeln!(io::stdout(), "{}", item)?;
    }

    Ok(())
}
